INSERT INTO public.spells (id, name, owner_id, source, visibility, level, school, casting_time, "range", components, duration, concentration, ritual, classes, description, higher_levels, save_type, attack_type, damage_dice, damage_type, damage_at_slot_level, damage_at_char_level, heal_dice, heal_at_slot_level, area_of_effect) VALUES
('acid-splash', 'Acid Splash', NULL, 'srd', 'private', 0, 'Conjuration', '1 action', '60 feet', 'V, S', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'You hurl a bubble of acid. Choose one creature within range, or choose two creatures within range that are within 5 feet of each other. A target must succeed on a dexterity saving throw or take 1d6 acid damage.\n\nThis spell''s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', NULL, 'DEX', NULL, '1d6', 'Acid', NULL, '{"1":"1d6","5":"2d6","11":"3d6","17":"4d6"}'::jsonb, NULL, NULL, NULL),
('chill-touch', 'Chill Touch', NULL, 'srd', 'private', 0, 'Necromancy', '1 action', '120 feet', 'V, S', '1 round', false, false, '{"Sorcerer","Warlock","Wizard"}', E'You create a ghostly, skeletal hand in the space of a creature within range. Make a ranged spell attack against the creature to assail it with the chill of the grave. On a hit, the target takes 1d8 necrotic damage, and it can''t regain hit points until the start of your next turn. Until then, the hand clings to the target.\n\nIf you hit an undead target, it also has disadvantage on attack rolls against you until the end of your next turn.\n\nThis spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', NULL, NULL, 'ranged', '1d8', 'Necrotic', NULL, '{"1":"1d8","5":"2d8","11":"3d8","17":"4d8"}'::jsonb, NULL, NULL, NULL),
('dancing-lights', 'Dancing Lights', NULL, 'srd', 'private', 0, 'Evocation', '1 action', '120 feet', 'V, S, M (A bit of phosphorus or wychwood, or a glowworm.)', 'Up to 1 minute', true, false, '{"Bard","Sorcerer","Wizard","Psion"}', E'You create up to four torch-sized lights within range, making them appear as torches, lanterns, or glowing orbs that hover in the air for the duration. You can also combine the four lights into one glowing vaguely humanoid form of Medium size. Whichever form you choose, each light sheds dim light in a 10-foot radius.\n\nAs a bonus action on your turn, you can move the lights up to 60 feet to a new spot within range. A light must be within 20 feet of another light created by this spell, and a light winks out if it exceeds the spell''s range.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('druidcraft', 'Druidcraft', NULL, 'srd', 'private', 0, 'Transmutation', '1 action', '30 feet', 'V, S', 'Instantaneous', false, false, '{"Druid"}', E'Whispering to the spirits of nature, you create one of the following effects within ''range'':\n\n- You create a tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. The effect might manifest as a golden orb for clear skies, a cloud for rain, falling snowflakes for snow, and so on. This effect persists for 1 round.\n\n- You instantly make a flower bloom, a seed pod open, or a leaf bud bloom.\n\n- You create an instantaneous, harmless sensory effect, such as falling leaves, a puff of wind, the sound of a small animal, or the faint order of skunk. The effect must fit in a 5-foot cube.\n\n- You instantly light or snuff out a candle, a torch, or a small campfire.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('eldritch-blast', 'Eldritch Blast', NULL, 'srd', 'private', 0, 'Evocation', '1 action', '120 feet', 'V, S', 'Instantaneous', false, false, '{"Warlock"}', 'A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 force damage. The spell creates more than one beam when you reach higher levels: two beams at 5th level, three beams at 11th level, and four beams at 17th level. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.', NULL, NULL, 'ranged', '1d10', 'Force', NULL, '{"1":"1d10","5":"1d10","11":"1d10","17":"1d10"}'::jsonb, NULL, NULL, NULL),
('fire-bolt', 'Fire Bolt', NULL, 'srd', 'private', 0, 'Evocation', '1 action', '120 feet', 'V, S', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'You hurl a mote of fire at a creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 fire damage. A flammable object hit by this spell ignites if it isn''t being worn or carried.\n\nThis spell''s damage increases by 1d10 when you reach 5th level (2d10), 11th level (3d10), and 17th level (4d10).', NULL, NULL, 'ranged', '1d10', 'Fire', NULL, '{"1":"1d10","5":"2d10","11":"3d10","17":"4d10"}'::jsonb, NULL, NULL, NULL),
('guidance', 'Guidance', NULL, 'srd', 'private', 0, 'Divination', '1 action', 'Touch', 'V, S', 'Up to 1 minute', true, false, '{"Cleric","Druid"}', 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one ability check of its choice. It can roll the die before or after making the ability check. The spell then ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('light', 'Light', NULL, 'srd', 'private', 0, 'Evocation', '1 action', 'Touch', 'V, M (A firefly or phosphorescent moss.)', '1 hour', false, false, '{"Bard","Cleric","Sorcerer","Wizard","Psion"}', E'You touch one object that is no larger than 10 feet in any dimension. Until the spell ends, the object sheds bright light in a 20-foot radius and dim light for an additional 20 feet. The light can be colored as you like. Completely covering the object with something opaque blocks the light. The spell ends if you cast it again or dismiss it as an action.\n\nIf you target an object held or worn by a hostile creature, that creature must succeed on a dexterity saving throw to avoid the spell.', NULL, 'DEX', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('mage-hand', 'Mage Hand', NULL, 'srd', 'private', 0, 'Conjuration', '1 action', '30 feet', 'V, S', '1 minute', false, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration or until you dismiss it as an action. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again.\n\nYou can use your action to control the hand. You can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial. You can move the hand up to 30 feet each time you use it.\n\nThe hand can''t attack, activate magic items, or carry more than 10 pounds.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('mending', 'Mending', NULL, 'srd', 'private', 0, 'Transmutation', '1 minute', 'Touch', 'V, S, M (Two lodestones.)', 'Instantaneous', false, false, '{"Cleric","Bard","Druid","Sorcerer","Wizard","Psion"}', E'This spell repairs a single break or tear in an object you touch, such as a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no longer than 1 foot in any dimension, you mend it, leaving no trace of the former damage.\n\nThis spell can physically repair a magic item or construct, but the spell can''t restore magic to such an object.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('message', 'Message', NULL, 'srd', 'private', 0, 'Transmutation', '1 action', '120 feet', 'V, S, M (A short piece of copper wire.)', '1 round', false, false, '{"Bard","Sorcerer","Wizard","Psion"}', E'You point your finger toward a creature within range and whisper a message. The target (and only the target) hears the message and can reply in a whisper that only you can hear.\n\nYou can cast this spell through solid objects if you are familiar with the target and know it is beyond the barrier. Magical silence, 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood blocks the spell. The spell doesn''t have to follow a straight line and can travel freely around corners or through openings.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('minor-illusion', 'Minor Illusion', NULL, 'srd', 'private', 0, 'Illusion', '1 action', '30 feet', 'S, M (A bit of fleece.)', '1 minute', false, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this spell again.\n\nIf you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else''s voice, a lion''s roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends.\n\nIf you create an image of an object--such as a chair, muddy footprints, or a small chest--it must be no larger than a 5-foot cube. The image can''t create sound, light, smell, or any other sensory effect. Physical interaction with the image reveals it to be an illusion, because things can pass through it.\n\nIf a creature uses its action to examine the sound or image, the creature can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the illusion becomes faint to the creature.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('poison-spray', 'Poison Spray', NULL, 'srd', 'private', 0, 'Conjuration', '1 action', '10 feet', 'V, S', 'Instantaneous', false, false, '{"Sorcerer","Warlock","Wizard","Druid"}', E'You extend your hand toward a creature you can see within range and project a puff of noxious gas from your palm. The creature must succeed on a constitution saving throw or take 1d12 poison damage.\n\nThis spell''s damage increases by 1d12 when you reach 5th level (2d12), 11th level (3d12), and 17th level (4d12).', NULL, 'CON', NULL, '1d12', 'Poison', NULL, '{"1":"1d12","5":"2d12","11":"3d12","17":"4d12"}'::jsonb, NULL, NULL, NULL),
('prestidigitation', 'Prestidigitation', NULL, 'srd', 'private', 0, 'Transmutation', '1 action', '10 feet', 'V, S', '1 hour', false, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'This spell is a minor magical trick that novice spellcasters use for practice. You create one of the following magical effects within ''range'':\n\nYou create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor.\n\nYou instantaneously light or snuff out a candle, a torch, or a small campfire.\n\nYou instantaneously clean or soil an object no larger than 1 cubic foot.\n\nYou chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour.\n\nYou make a color, a small mark, or a symbol appear on an object or a surface for 1 hour.\n\nYou create a nonmagical trinket or an illusory image that can fit in your hand and that lasts until the end of your next turn.\n\nIf you cast this spell multiple times, you can have up to three of its non-instantaneous effects active at a time, and you can dismiss such an effect as an action.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('produce-flame', 'Produce Flame', NULL, 'srd', 'private', 0, 'Conjuration', '1 action', 'Self', 'V, S', '10 minutes', false, false, '{"Druid"}', E'A flickering flame appears in your hand. The flame remains there for the duration and harms neither you nor your equipment. The flame sheds bright light in a 10-foot radius and dim light for an additional 10 feet. The spell ends if you dismiss it as an action or if you cast it again.\n\nYou can also attack with the flame, although doing so ends the spell. When you cast this spell, or as an action on a later turn, you can hurl the flame at a creature within 30 feet of you. Make a ranged spell attack. On a hit, the target takes 1d8 fire damage.\n\nThis spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', NULL, NULL, 'ranged', '1d8', 'Fire', NULL, '{"1":"1d8","5":"2d8","11":"3d8","17":"4d8"}'::jsonb, NULL, NULL, NULL),
('ray-of-frost', 'Ray of Frost', NULL, 'srd', 'private', 0, 'Evocation', '1 action', '60 feet', 'V, S', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 cold damage, and its speed is reduced by 10 feet until the start of your next turn.\n\nThe spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', NULL, NULL, 'ranged', '1d8', 'Cold', NULL, '{"1":"1d8","5":"2d8","11":"3d8","17":"4d8"}'::jsonb, NULL, NULL, NULL),
('resistance', 'Resistance', NULL, 'srd', 'private', 0, 'Abjuration', '1 action', 'Touch', 'V, S, M (A miniature cloak.)', 'Up to 1 minute', true, false, '{"Cleric","Druid"}', 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one saving throw of its choice. It can roll the die before or after making the saving throw. The spell then ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('sacred-flame', 'Sacred Flame', NULL, 'srd', 'private', 0, 'Evocation', '1 action', '60 feet', 'V, S', 'Instantaneous', false, false, '{"Cleric"}', E'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a dexterity saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw.\n\nThe spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', NULL, 'DEX', NULL, '1d8', 'Radiant', NULL, '{"1":"1d8","5":"2d8","11":"3d8","17":"4d8"}'::jsonb, NULL, NULL, NULL),
('shillelagh', 'Shillelagh', NULL, 'srd', 'private', 0, 'Transmutation', '1 bonus action', 'Touch', 'V, S, M (Mistletoe, a shamrock leaf, and a club or quarterstaff.)', '1 minute', false, false, '{"Druid"}', 'The wood of a club or a quarterstaff you are holding is imbued with nature''s power. For the duration, you can use your spellcasting ability instead of Strength for the attack and damage rolls of melee attacks using that weapon, and the weapon''s damage die becomes a d8. The weapon also becomes magical, if it isn''t already. The spell ends if you cast it again or if you let go of the weapon.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('shocking-grasp', 'Shocking Grasp', NULL, 'srd', 'private', 0, 'Evocation', '1 action', 'Touch', 'V, S', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'Lightning springs from your hand to deliver a shock to a creature you try to touch. Make a melee spell attack against the target. You have advantage on the attack roll if the target is wearing armor made of metal. On a hit, the target takes 1d8 lightning damage, and it can''t take reactions until the start of its next turn.\n\nThe spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', NULL, NULL, 'melee', '1d8', 'Lightning', NULL, '{"1":"1d8","5":"2d8","11":"3d8","17":"4d8"}'::jsonb, NULL, NULL, NULL),
('spare-the-dying', 'Spare the Dying', NULL, 'srd', 'private', 0, 'Necromancy', '1 action', 'Touch', 'V, S', 'Instantaneous', false, false, '{"Cleric"}', 'You touch a living creature that has 0 hit points. The creature becomes stable. This spell has no effect on undead or constructs.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('thaumaturgy', 'Thaumaturgy', NULL, 'srd', 'private', 0, 'Transmutation', '1 action', '30 feet', 'V', '1 minute', false, false, '{"Cleric"}', E'You manifest a minor wonder, a sign of supernatural power, within range. You create one of the following magical effects within range.\n\n- Your voice booms up to three times as loud as normal for 1 minute.\n\n- You cause flames to flicker, brighten, dim, or change color for 1 minute.\n\n- You cause harmless tremors in the ground for 1 minute.\n\n- You create an instantaneous sound that originates from a point of your choice within range, such as a rumble of thunder, the cry of a raven, or ominous whispers.\n\n- You instantaneously cause an unlocked door or window to fly open or slam shut.\n\n- You alter the appearance of your eyes for 1 minute.\n\nIf you cast this spell multiple times, you can have up to three of its 1-minute effects active at a time, and you can dismiss such an effect as an action.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('true-strike', 'True Strike', NULL, 'srd', 'private', 0, 'Divination', '1 action', '30 feet', 'S', 'Up to 1 round', true, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', 'You extend your hand and point a finger at a target in range. Your magic grants you a brief insight into the target''s defenses. On your next turn, you gain advantage on your first attack roll against the target, provided that this spell hasn''t ended.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('vicious-mockery', 'Vicious Mockery', NULL, 'srd', 'private', 0, 'Enchantment', '1 action', '60 feet', 'V', 'Instantaneous', false, false, '{"Bard"}', E'You unleash a string of insults laced with subtle enchantments at a creature you can see within range. If the target can hear you (though it need not understand you), it must succeed on a wisdom saving throw or take 1d4 psychic damage and have disadvantage on the next attack roll it makes before the end of its next turn.\n\nThis spell''s damage increases by 1d4 when you reach 5th level (2d4), 11th level (3d4), and 17th level (4d4).', NULL, 'WIS', NULL, '1d4', 'Psychic', NULL, '{"1":"1d4","5":"2d4","11":"3d4","17":"4d4"}'::jsonb, NULL, NULL, NULL),
('alarm', 'Alarm', NULL, 'srd', 'private', 1, 'Abjuration', '1 minute', '30 feet', 'V, S, M (A tiny bell and a piece of fine silver wire.)', '8 hours', false, true, '{"Ranger","Wizard"}', E'You set an alarm against unwanted intrusion. Choose a door, a window, or an area within range that is no larger than a 20-foot cube. Until the spell ends, an alarm alerts you whenever a Tiny or larger creature touches or enters the warded area. When you cast the spell, you can designate creatures that won''t set off the alarm. You also choose whether the alarm is mental or audible.\n\nA mental alarm alerts you with a ping in your mind if you are within 1 mile of the warded area. This ping awakens you if you are sleeping.\n\nAn audible alarm produces the sound of a hand bell for 10 seconds within 60 feet.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":20}'::jsonb),
('animal-friendship', 'Animal Friendship', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', '30 feet', 'V, S, M (A morsel of food.)', '24 hours', false, false, '{"Bard","Druid","Ranger","Psion"}', 'This spell lets you convince a beast that you mean it no harm. Choose a beast that you can see within range. It must see and hear you. If the beast''s Intelligence is 4 or higher, the spell fails. Otherwise, the beast must succeed on a wisdom saving throw or be charmed by you for the spell''s duration. If you or one of your companions harms the target, the spells ends.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('bane', 'Bane', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', '30 feet', 'V, S, M (A drop of blood.)', 'Up to 1 minute', true, false, '{"Bard","Cleric"}', 'Up to three creatures of your choice that you can see within range must make charisma saving throws. Whenever a target that fails this saving throw makes an attack roll or a saving throw before the spell ends, the target must roll a d4 and subtract the number rolled from the attack roll or saving throw.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', 'CHA', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('bless', 'Bless', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', '30 feet', 'V, S, M (A sprinkling of holy water.)', 'Up to 1 minute', true, false, '{"Cleric","Paladin"}', 'You bless up to three creatures of your choice within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target can roll a d4 and add the number rolled to the attack roll or saving throw.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('burning-hands', 'Burning Hands', NULL, 'srd', 'private', 1, 'Evocation', '1 action', 'Self', 'V, S', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'As you hold your hands with thumbs touching and fingers spread, a thin sheet of flames shoots forth from your outstretched fingertips. Each creature in a 15-foot cone must make a dexterity saving throw. A creature takes 3d6 fire damage on a failed save, or half as much damage on a successful one.\n\nThe fire ignites any flammable objects in the area that aren''t being worn or carried.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', 'DEX', NULL, '3d6', 'Fire', '{"1":"3d6","2":"4d6","3":"5d6","4":"6d6","5":"7d6","6":"8d6","7":"9d6","8":"10d6","9":"11d6"}'::jsonb, NULL, NULL, NULL, '{"type":"cone","size":15}'::jsonb),
('charm-person', 'Charm Person', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', '30 feet', 'V, S', '1 hour', false, false, '{"Bard","Druid","Sorcerer","Warlock","Wizard","Psion"}', 'You attempt to charm a humanoid you can see within range. It must make a wisdom saving throw, and does so with advantage if you or your companions are fighting it. If it fails the saving throw, it is charmed by you until the spell ends or until you or your companions do anything harmful to it. The charmed creature regards you as a friendly acquaintance. When the spell ends, the creature knows it was charmed by you.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st. The creatures must be within 30 feet of each other when you target them.', 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('color-spray', 'Color Spray', NULL, 'srd', 'private', 1, 'Illusion', '1 action', 'Self', 'V, S, M (A pinch of powder or sand that is colored red, yellow, and blue.)', '1 round', false, false, '{"Sorcerer","Wizard"}', E'A dazzling array of flashing, colored light springs from your hand. Roll 6d10; the total is how many hit points of creatures this spell can effect. Creatures in a 15-foot cone originating from you are affected in ascending order of their current hit points (ignoring unconscious creatures and creatures that can''t see).\n\nStarting with the creature that has the lowest current hit points, each creature affected by this spell is blinded until the spell ends. Subtract each creature''s hit points from the total before moving on to the creature with the next lowest hit points. A creature''s hit points must be equal to or less than the remaining total for that creature to be affected.', 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d10 for each slot level above 1st.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cone","size":15}'::jsonb),
('command', 'Command', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', '60 feet', 'V', '1 round', false, false, '{"Cleric","Paladin","Psion"}', E'You speak a one-word command to a creature you can see within range. The target must succeed on a wisdom saving throw or follow the command on its next turn. The spell has no effect if the target is undead, if it doesn''t understand your language, or if your command is directly harmful to it.\n\nSome typical commands and their effects follow. You might issue a command other than one described here. If you do so, the GM determines how the target behaves. If the target can''t follow your command, the spell ends.\n\n***Approach.*** The target moves toward you by the shortest and most direct route, ending its turn if it moves within 5 feet of you.\n\n***Drop.*** The target drops whatever it is holding and then ends its turn.\n\n***Flee.*** The target spends its turn moving away from you by the fastest available means.\n\n***Grovel.*** The target falls prone and then ends its turn.\n\n***Halt.*** The target doesn''t move and takes no actions. A flying creature stays aloft, provided that it is able to do so. If it must move to stay aloft, it flies the minimum distance needed to remain in the air.', 'When you cast this spell using a spell slot of 2nd level or higher, you can affect one additional creature for each slot level above 1st. The creatures must be within 30 feet of each other when you target them.', 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('comprehend-languages', 'Comprehend Languages', NULL, 'srd', 'private', 1, 'Divination', '1 action', 'Self', 'V, S, M (A pinch of soot and salt.)', '1 hour', false, true, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching the surface on which the words are written. It takes about 1 minute to read one page of text.\n\nThis spell doesn''t decode secret messages in a text or a glyph, such as an arcane sigil, that isn''t part of a written language.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('create-or-destroy-water', 'Create or Destroy Water', NULL, 'srd', 'private', 1, 'Transmutation', '1 action', '30 feet', 'V, S, M (A drop of water if creating water, or a few grains of sand if destroying it.)', 'Instantaneous', false, false, '{"Cleric","Druid"}', E'You either create or destroy water.\n\n***Create Water.*** You create up to 10 gallons of clean water within range in an open container. Alternatively, the water falls as rain in a 30-foot cube within range.\n\n***Destroy Water.*** You destroy up to 10 gallons of water in an open container within range. Alternatively, you destroy fog in a 30-foot cube within range.', 'When you cast this spell using a spell slot of 2nd level or higher, you create or destroy 10 additional gallons of water, or the size of the cube increases by 5 feet, for each slot level above 1st.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":30}'::jsonb),
('cure-wounds', 'Cure Wounds', NULL, 'srd', 'private', 1, 'Evocation', '1 action', 'Touch', 'V, S', 'Instantaneous', false, false, '{"Bard","Cleric","Druid","Paladin","Ranger"}', 'A creature you touch regains a number of hit points equal to 1d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d8 for each slot level above 1st.', NULL, NULL, NULL, NULL, NULL, NULL, '1d8 + MOD', '{"1":"1d8 + MOD","2":"2d8 + MOD","3":"3d8 + MOD","4":"4d8 + MOD","5":"5d8 + MOD","6":"6d8 + MOD","7":"7d8 + MOD","8":"8d8 + MOD","9":"9d8 + MOD"}'::jsonb, NULL),
('detect-evil-and-good', 'Detect Evil and Good', NULL, 'srd', 'private', 1, 'Divination', '1 action', 'Self', 'V, S', 'Up to 10 minutes', true, false, '{"Cleric","Paladin"}', E'For the duration, you know if there is an aberration, celestial, elemental, fey, fiend, or undead within 30 feet of you, as well as where the creature is located. Similarly, you know if there is a place or object within 30 feet of you that has been magically consecrated or desecrated.\n\nThe spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":30}'::jsonb),
('detect-magic', 'Detect Magic', NULL, 'srd', 'private', 1, 'Divination', '1 action', 'Self', 'V, S', 'Up to 10 minutes', true, true, '{"Bard","Cleric","Druid","Paladin","Ranger","Sorcerer","Wizard","Psion"}', E'For the duration, you sense the presence of magic within 30 feet of you. If you sense magic in this way, you can use your action to see a faint aura around any visible creature or object in the area that bears magic, and you learn its school of magic, if any.\n\nThe spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":30}'::jsonb),
('detect-poison-and-disease', 'Detect Poison and Disease', NULL, 'srd', 'private', 1, 'Divination', '1 action', 'Self', 'V, S, M (A yew leaf.)', 'Up to 10 minutes', true, true, '{"Cleric","Druid","Paladin","Ranger"}', E'For the duration, you can sense the presence and location of poisons, poisonous creatures, and diseases within 30 feet of you. You also identify the kind of poison, poisonous creature, or disease in each case.\n\nThe spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":30}'::jsonb),
('disguise-self', 'Disguise Self', NULL, 'srd', 'private', 1, 'Illusion', '1 action', 'Self', 'V, S', '1 hour', false, false, '{"Bard","Sorcerer","Wizard"}', E'You make yourself--including your clothing, armor, weapons, and other belongings on your person--look different until the spell ends or until you use your action to dismiss it. You can seem 1 foot shorter or taller and can appear thin, fat, or in between. You can''t change your body type, so you must adopt a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you.\n\nThe changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to your outfit, objects pass through the hat, and anyone who touches it would feel nothing or would feel your head and hair. If you use this spell to appear thinner than you are, the hand of someone who reaches out to touch you would bump into you while it was seemingly still in midair.\n\nTo discern that you are disguised, a creature can use its action to inspect your appearance and must succeed on an Intelligence (Investigation) check against your spell save DC.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('divine-favor', 'Divine Favor', NULL, 'srd', 'private', 1, 'Evocation', '1 bonus action', 'Self', 'V, S', 'Up to 1 minute', true, false, '{"Paladin"}', 'Your prayer empowers you with divine radiance. Until the spell ends, your weapon attacks deal an extra 1d4 radiant damage on a hit.', NULL, NULL, NULL, '1d4', 'Radiant', '{"1":"1d4"}'::jsonb, NULL, NULL, NULL, NULL),
('entangle', 'Entangle', NULL, 'srd', 'private', 1, 'Conjuration', '1 action', '90 feet', 'V, S', 'Up to 1 minute', true, false, '{"Druid"}', E'Grasping weeds and vines sprout from the ground in a 20-foot square starting form a point within range. For the duration, these plants turn the ground in the area into difficult terrain.\n\nA creature in the area when you cast the spell must succeed on a strength saving throw or be restrained by the entangling plants until the spell ends. A creature restrained by the plants can use its action to make a Strength check against your spell save DC. On a success, it frees itself.\n\nWhen the spell ends, the conjured plants wilt away.', NULL, 'STR', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":20}'::jsonb),
('expeditious-retreat', 'Expeditious Retreat', NULL, 'srd', 'private', 1, 'Transmutation', '1 bonus action', 'Self', 'V, S', 'Up to 10 minutes', true, false, '{"Sorcerer","Warlock","Wizard"}', 'This spell allows you to move at an incredible pace. When you cast this spell, and then as a bonus action on each of your turns until the spell ends, you can take the Dash action.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('faerie-fire', 'Faerie Fire', NULL, 'srd', 'private', 1, 'Evocation', '1 action', '60 feet', 'V', 'Up to 1 minute', true, false, '{"Druid"}', E'Each object in a 20-foot cube within range is outlined in blue, green, or violet light (your choice). Any creature in the area when the spell is cast is also outlined in light if it fails a dexterity saving throw. For the duration, objects and affected creatures shed dim light in a 10-foot radius.\n\nAny attack roll against an affected creature or object has advantage if the attacker can see it, and the affected creature or object can''t benefit from being invisible.', NULL, 'DEX', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":20}'::jsonb),
('false-life', 'False Life', NULL, 'srd', 'private', 1, 'Necromancy', '1 action', 'Self', 'V, S, M (A small amount of alcohol or distilled spirits.)', '1 hour', false, false, '{"Sorcerer","Wizard"}', 'Bolstering yourself with a necromantic facsimile of life, you gain 1d4 + 4 temporary hit points for the duration.', 'When you cast this spell using a spell slot of 2nd level or higher, you gain 5 additional temporary hit points for each slot level above 1st.', NULL, NULL, NULL, NULL, NULL, NULL, '1d4 + 4', '{"1":"1d4 + 4","2":"1d4 + 9","3":"1d4 + 14","4":"1d4 + 19","5":"1d4 + 24","6":"1d4 + 29","7":"1d4 + 34","8":"1d4 + 39","9":"1d4 + 44"}'::jsonb, NULL),
('feather-fall', 'Feather Fall', NULL, 'srd', 'private', 1, 'Transmutation', '1 reaction', '60 feet', 'V, M (A small feather or a piece of down.)', '1 minute', false, false, '{"Bard","Sorcerer","Wizard","Psion"}', 'Choose up to five falling creatures within range. A falling creature''s rate of descent slows to 60 feet per round until the spell ends. If the creature lands before the spell ends, it takes no falling damage and can land on its feet, and the spell ends for that creature.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('find-familiar', 'Find Familiar', NULL, 'srd', 'private', 1, 'Conjuration', '1 hour', '10 feet', 'V, S, M (10gp worth of charcoal, incense, and herbs that must be consumed by fire in a brass brazier.)', 'Instantaneous', false, true, '{"Wizard"}', E'You gain the service of a familiar, a spirit that takes an animal form you choose: bat, cat, crab, frog (toad), hawk, lizard, octopus, owl, poisonous snake, fish (quipper), rat, raven, sea horse, spider, or weasel. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of a beast.\n\nYour familiar acts independently of you, but it always obeys your commands. In combat, it rolls its own initiative and acts on its own turn. A familiar can''t attack, but it can take other actions as normal.\n\nWhen the familiar drops to 0 hit points, it disappears, leaving behind no physical form. It reappears after you cast this spell again.\n\nWhile your familiar is within 100 feet of you, you can communicate with it telepathically. Additionally, as an action, you can see through your familiar''s eyes and hear what it hears until the start of your next turn, gaining the benefits of any special senses that the familiar has. During this time, you are deaf and blind with regard to your own senses.\n\nAs an action, you can temporarily dismiss your familiar. It disappears into a pocket dimension where it awaits your summons. Alternatively, you can dismiss it forever. As an action while it is temporarily dismissed, you can cause it to reappear in any unoccupied space within 30 feet of you.\n\nYou can''t have more than one familiar at a time. If you cast this spell while you already have a familiar, you instead cause it to adopt a new form. Choose one of the forms from the above list. Your familiar transforms into the chosen creature.\n\nFinally, when you cast a spell with a range of touch, your familiar can deliver the spell as if it had cast the spell. Your familiar must be within 100 feet of you, and it must use its reaction to deliver the spell when you cast it. If the spell requires an attack roll, you use your action modifier for the roll.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('floating-disk', 'Floating Disk', NULL, 'srd', 'private', 1, 'Conjuration', '1 action', '30 feet', 'V, S, M (A drop of mercury.)', '1 hour', false, true, '{"Wizard"}', E'This spell creates a circular, horizontal plane of force, 3 feet in diameter and 1 inch thick, that floats 3 feet above the ground in an unoccupied space of your choice that you can see within range. The disk remains for the duration, and can hold up to 500 pounds. If more weight is placed on it, the spell ends, and everything on the disk falls to the ground.\n\nThe disk is immobile while you are within 20 feet of it. If you move more than 20 feet away from it, the disk follows you so that it remains within 20 feet of you. If can move across uneven terrain, up or down stairs, slopes and the like, but it can''t cross an elevation change of 10 feet or more. For example, the disk can''t move across a 10-foot-deep pit, nor could it leave such a pit if it was created at the bottom.\n\nIf you move more than 100 feet away from the disk (typically because it can''t move around an obstacle to follow you), the spell ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('fog-cloud', 'Fog Cloud', NULL, 'srd', 'private', 1, 'Conjuration', '1 action', '120 feet', 'V, S', 'Up to 1 hour', true, false, '{"Druid","Ranger","Sorcerer","Wizard"}', 'You create a 20-foot-radius sphere of fog centered on a point within range. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it.', 'When you cast this spell using a spell slot of 2nd level or higher, the radius of the fog increases by 20 feet for each slot level above 1st.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":20}'::jsonb),
('goodberry', 'Goodberry', NULL, 'srd', 'private', 1, 'Transmutation', '1 action', 'Touch', 'V, S, M (A sprig of mistletoe.)', 'Instantaneous', false, false, '{"Druid","Ranger"}', E'Up to ten berries appear in your hand and are infused with magic for the duration. A creature can use its action to eat one berry. Eating a berry restores 1 hit point, and the berry provides enough nourishment to sustain a creature for a day.\n\nThe berries lose their potency if they have not been consumed within 24 hours of the casting of this spell.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('grease', 'Grease', NULL, 'srd', 'private', 1, 'Conjuration', '1 action', '60 feet', 'V, S, M (A bit of pork rind or butter.)', '1 minute', false, false, '{"Wizard"}', E'Slick grease covers the ground in a 10-foot square centered on a point within range and turns it into difficult terrain for the duration.\n\nWhen the grease appears, each creature standing in its area must succeed on a dexterity saving throw or fall prone. A creature that enters the area or ends its turn there must also succeed on a dexterity saving throw or fall prone.', NULL, 'DEX', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":10}'::jsonb)
